import{_ as s,o as r,c as i,ag as t}from"./chunks/framework.CvgP6Fyv.js";const g=JSON.parse('{"title":"Depenses","description":"","frontmatter":{},"headers":[],"relativePath":"fr/features/expenses.md","filePath":"fr/features/expenses.md"}'),a={name:"fr/features/expenses.md"};function n(l,e,o,u,p,d){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="depenses" tabindex="-1">Depenses <a class="header-anchor" href="#depenses" aria-label="Permalink to &quot;Depenses&quot;">​</a></h1><p>Suivez toutes vos depenses professionnelles, numerisez des recus avec l&#39;IA et categorisez les couts pour une comptabilite precise et la declaration de TVA.</p><h2 id="vue-d-ensemble" tabindex="-1">Vue d&#39;ensemble <a class="header-anchor" href="#vue-d-ensemble" aria-label="Permalink to &quot;Vue d&#39;ensemble&quot;">​</a></h2><p>La page des depenses repertorie toutes vos depenses enregistrees. Filtrez par :</p><ul><li><strong>Categorie</strong> -- Bureau, deplacement, equipement, etc.</li><li><strong>Projet</strong> -- Depenses liees a des projets specifiques</li><li><strong>Plage de dates</strong> -- Filtrer par date de depense</li><li><strong>Statut</strong> -- Active ou archivee</li></ul><h2 id="creer-une-depense" tabindex="-1">Creer une depense <a class="header-anchor" href="#creer-une-depense" aria-label="Permalink to &quot;Creer une depense&quot;">​</a></h2><h3 id="saisie-manuelle" tabindex="-1">Saisie manuelle <a class="header-anchor" href="#saisie-manuelle" aria-label="Permalink to &quot;Saisie manuelle&quot;">​</a></h3><ol><li>Allez dans <strong>Depenses &gt; Nouvelle depense</strong></li><li>Remplissez : <ul><li><strong>Description</strong> -- L&#39;objet de la depense</li><li><strong>Montant</strong> -- Cout total (TTC ou HT)</li><li><strong>Date</strong> -- Date de la depense</li><li><strong>Categorie</strong> -- Selectionnez parmi les categories predefinies</li><li><strong>Taux de TVA</strong> -- Pourcentage de TVA applicable</li></ul></li><li>Joignez optionnellement une image ou un PDF de <strong>recu</strong></li><li>Liez optionnellement a un <strong>projet</strong> ou un <strong>client</strong></li><li>Cliquez sur <strong>Enregistrer</strong></li></ol><h3 id="ajout-rapide" tabindex="-1">Ajout rapide <a class="header-anchor" href="#ajout-rapide" aria-label="Permalink to &quot;Ajout rapide&quot;">​</a></h3><p>Utilisez le tiroir d&#39;ajout rapide pour une saisie rapide de depenses :</p><ol><li>Cliquez sur le bouton d&#39;ajout rapide dans la liste des depenses</li><li>Entrez le montant et la description</li><li>Selectionnez une categorie rapide</li><li>Enregistrez</li></ol><h3 id="numerisation-de-recus" tabindex="-1">Numerisation de recus <a class="header-anchor" href="#numerisation-de-recus" aria-label="Permalink to &quot;Numerisation de recus&quot;">​</a></h3><p>Laissez l&#39;IA extraire automatiquement les details de vos recus :</p><ol><li>Allez dans <strong>Depenses &gt; Numeriser un recu</strong></li><li>Telechargez une image de recu (JPEG, PNG, WebP) ou un PDF</li><li>Choisissez le mode d&#39;extraction : <ul><li><strong>Simple</strong> -- Une depense a partir du recu</li><li><strong>Multiple</strong> -- Plusieurs lignes a partir d&#39;un seul recu</li></ul></li><li>Verifiez les donnees extraites (date, montant, fournisseur, description)</li><li>Confirmez pour creer la ou les depenses</li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><p>La numerisation de recus necessite le plan <strong>Pro</strong> ou superieur.</p></div><h2 id="categories-de-depenses" tabindex="-1">Categories de depenses <a class="header-anchor" href="#categories-de-depenses" aria-label="Permalink to &quot;Categories de depenses&quot;">​</a></h2><p>MyCompanyDesk propose des categories predefinies avec des icones pour une selection rapide :</p><ul><li>Fournitures de bureau</li><li>Deplacements et transports</li><li>Restauration et boissons</li><li>Logiciels et abonnements</li><li>Equipement</li><li>Services professionnels</li><li>Marketing et publicite</li><li>Assurance</li><li>Loyer et charges</li><li>Et bien d&#39;autres...</li></ul><p>Les categories aident a organiser vos depenses et sont utilisees dans les rapports pour les ventilations de couts.</p><h2 id="gestion-de-la-tva" tabindex="-1">Gestion de la TVA <a class="header-anchor" href="#gestion-de-la-tva" aria-label="Permalink to &quot;Gestion de la TVA&quot;">​</a></h2><p>Chaque depense peut avoir son propre taux de TVA. Options courantes :</p><ul><li><strong>21 %</strong> -- Taux normal</li><li><strong>9 %</strong> -- Taux reduit</li><li><strong>0 %</strong> -- Taux zero ou exonere</li></ul><p>Le montant de TVA est calcule automatiquement et inclus dans vos <a href="/fr/features/vat">rapports de TVA</a>.</p><h2 id="lier-les-depenses" tabindex="-1">Lier les depenses <a class="header-anchor" href="#lier-les-depenses" aria-label="Permalink to &quot;Lier les depenses&quot;">​</a></h2><p>Liez les depenses a :</p><ul><li><strong>Projets</strong> -- Suivez precisement les couts par projet</li><li><strong>Clients</strong> -- Associez les couts a des clients specifiques</li><li><strong>Fournisseurs</strong> -- Enregistrez a qui vous avez paye</li></ul><h2 id="actions-groupees" tabindex="-1">Actions groupees <a class="header-anchor" href="#actions-groupees" aria-label="Permalink to &quot;Actions groupees&quot;">​</a></h2><p>Selectionnez plusieurs depenses pour :</p><ul><li><strong>Categoriser</strong> -- Changer la categorie en masse</li><li><strong>Archiver</strong> -- Deplacer vers les archives</li><li><strong>Supprimer</strong> -- Supprimer definitivement</li><li><strong>Exporter</strong> -- Telecharger au format CSV</li></ul><h2 id="depenses-recurrentes" tabindex="-1">Depenses recurrentes <a class="header-anchor" href="#depenses-recurrentes" aria-label="Permalink to &quot;Depenses recurrentes&quot;">​</a></h2><p>Pour les couts reguliers (loyer, abonnements, etc.), configurez des <a href="/fr/features/recurring-expenses">depenses recurrentes</a> pour automatiser la creation.</p><h2 id="import" tabindex="-1">Import <a class="header-anchor" href="#import" aria-label="Permalink to &quot;Import&quot;">​</a></h2><p>Importez des depenses depuis un fichier CSV :</p><ol><li>Allez dans <strong>Profil &gt; Import</strong></li><li>Selectionnez <strong>Depenses</strong> comme type de donnees</li><li>Telechargez votre fichier CSV</li><li>Faites correspondre les colonnes aux champs</li><li>Verifiez et confirmez</li></ol><h2 id="conseils" tabindex="-1">Conseils <a class="header-anchor" href="#conseils" aria-label="Permalink to &quot;Conseils&quot;">​</a></h2><ul><li>Activez les <a href="/fr/advanced/ai-features">suggestions IA</a> pour des recommandations automatiques de categories</li><li>Joignez toujours les recus -- ils sont essentiels pour les controles fiscaux</li><li>Utilisez les projets pour suivre le ratio depenses/revenus</li><li>Consultez le <a href="/fr/features/reports">rapport de depenses</a> pour les ventilations de couts</li></ul>',36)])])}const h=s(a,[["render",n]]);export{g as __pageData,h as default};
